sections.solution:
import Foundation

class CancellableStore {
    var items: [String] = []

    func store(_ item: String) {
        items.append(item)
    }

    func cancelAll() -> Int {
        let count = items.count
        items.removeAll()
        return count
    }
}

let store = CancellableStore()
store.store("subscription-A")
store.store("subscription-B")
print("Cancelled \(store.cancelAll()) subscriptions")
